def merge_cells(data):
    if not data:
        return []

    merged_data = []
    previous_row = None

    for row in data:
        if previous_row is None:
            merged_data.append(row)
            previous_row = row
            continue

        new_row = []
        for i in range(len(row)):
            if row[i] == previous_row[i]:
                new_row.append("")  # Merge cell
            else:
                new_row.append(row[i])  # Keep cell
        merged_data.append(new_row)
        previous_row = row

    return merged_data

def solve(data):
    return merge_cells(data)
